const prospect = $('Batch Prospects').item.json;
const firstName = (prospect.contact_name || 'there').split(' ')[0];

const subject = `Collaboration opportunity with ${prospect.client_name}`;

const body = `Hi ${firstName},

I came across ${prospect.domain} and really enjoyed your content. I'm reaching out from ${prospect.client_name} (${prospect.client_domain}) to explore a potential collaboration.

We'd love to contribute a guest article to your site that would be valuable to your readers. We have several topic ideas that align well with your audience.

Would you be open to discussing this? Happy to share our content ideas.

Best regards,
${prospect.client_name} Team`;

return [{
  json: {
    ...prospect,
    subject,
    body,
    to: prospect.contact_email
  }
}];
